content.partialArgs:
{"command": "# 看看 agent 配置详情
cat ~/.openclaw/agents/main/agent/config.yaml 2>/dev/null || echo "无独立config文件"
echo
echo "=== agents 配置 ==="
cat ~/.openclaw/openclaw.json 2>/dev/null | python3 -c "
import sys,json
try:
    d=json.load(sys.stdin)
    agents = d.get('agents',{})
    if isinstance(agents, dict) and 'entries' in agents:
        for name, cfg in agents['entries'].items():
            print(f'  {name}: primary_model={cfg.get(\"model\",{}).get(\"primary\",\"?\")}')
    elif isinstance(agents, dict):
        # 如果是merge模式
        defaults = agents.get('defaults',{})
        print(f'  defaults: model={defaults.get(\"model\",{}).get(\"primary\",\"?\")}')
        print(f'  workspace={defaults.get(\"workspace\",\"?\")}')
except Exception as e:
    print(f'解析失败: {e}')
""}

